function OnPiratesScenario_DeleteUnitsAtGoal(targetInfo)
    -- 删除已到达出口单元格的宝藏舰队单位
    local treasurePlotIndex = Game:GetProperty("TreasureFleetPlotIndex");
    if treasurePlotIndex == nil then
        return true;
    end
    local treasurePlot = Map.GetPlotByIndex(treasurePlotIndex);
    if treasurePlot == nil then
        return true;
    end
    local treasurePlotUnits = Map.GetUnitsAt(treasurePlot);
    if treasurePlotUnits ~= nil then
        for PlotUnit in treasurePlotUnits:Units() do
            if PlotUnit:GetOwner() ~= NO_PLAYER then
                local pOwner = Players[PlotUnit:GetOwner()];
                pOwner:GetUnits():Destroy(PlotUnit);
            end
        end
    end
    targetInfo.Extra = 1;
    return true;
end
GameEvents.PiratesScenario_DeleteUnitsAtGoal.Add(OnPiratesScenario_DeleteUnitsAtGoal);

