function ScenarioCommand_Minister(eOwner, iUnitID)
    local pPlayer = Players[eOwner];
    if (pPlayer == nil) then
        return;
    end

    local pUnit = pPlayer:GetUnits():FindID(iUnitID);
    if (pUnit == nil) then
        return;
    end

    -- 将单元格瘟疫回合数减半
    local Plot = Map.GetPlot(pUnit:GetX(), pUnit:GetY());
    local iPlagueTurns = RefreshObjectState(Plot, g_PropertyKeys.Plague) or 1;
    local iNewPlagueTurns = math.ceil(iPlagueTurns / 2);
    if (iPlagueTurns == 1) then
        iNewPlagueTurns = 0;
    end
    SetObjectState(Plot, g_PropertyKeys.Plague, iNewPlagueTurns);

    -- 消耗充能次数，用完则移除单位
    local iNumChargesUsed = GetObjectState(pUnit, g_PropertyKeys.Charges) or 1;
    SetObjectState(pUnit, g_PropertyKeys.Charges, iNumChargesUsed);
    UnitManager.FinishMoves(pUnit);
end
GameEvents.ScenarioCommand_Minister.Add(ScenarioCommand_Minister)

