function OnShowUnitFlagCombatPreview(damageToDefender, playerID, unitID)
    local kFlag = GetUnitFlag(playerID, unitID);
    if (kFlag == nil) then
        return;
    end
    local uiFlag = kFlag.m_Instance;
    if (uiFlag == nil) then
        return;
    end
    local damage = damageToDefender / 100;
    local pUnit = kFlag:GetUnit();
    local healthPercent = (pUnit:GetMaxDamage() - pUnit:GetDamage()) / pUnit:GetMaxDamage();
    local resultingHealthPercent = healthPercent - damage;
    uiFlag.CombatBar:SetPercent(resultingHealthPercent);
    uiFlag.CombatBar:SetShadowPercent(healthPercent);
    uiFlag.FlashingCombatBar:SetPercent(healthPercent);
end
LuaEvents.UnitPanel_CivRoyaleScenarioShowUnitFlagCombatPreview.Add(OnShowUnitFlagCombatPreview)

